INSERT INTO #temp_table SELECT CTA.ID_NUMBER, CTA.CIF_KEY, CUST.CUSTOMER_NAME, CUST.CIF_OPEN_BRANCH_CODE, CUST.CIF_OPEN_BRANCH, CUST.CUST_TYPE_CODE, CUST.CIF_OPEN_REGION_CODE, CUST.CIF_OPEN_REGION, CUST.SEGMENT_DIV_OWNER, CUST.SUB_SEGMENT, CUST.DIR_OWNER, CTA.ACCOUNT_TYPE, CTA.SUB_CATEGORY, CTA.PRODUCT_NAME, CTA.CURRENCY, CTA.BRANCH_CODE, CTA.SUBBRANCH_CODE, CTA.ACCT_APPROVAL_DATE, CTA.ACCT_OPEN_DATE, CTA.ACCT_EXPIRY_DATE, CTA.GL_CLASS_CODE, CTA.GL_ACCOUNT_ID, CTA.MARKET_SEGMENT_CD, CTA.ACCOUNT_STATUS, CTA.RATE, CTA.APPROVAL_AMT, CTA.APPROVAL_AMT_IDR, CTA.CUR_BOOK_BAL, CTA.CUR_BOOK_BAL_IDR, CTA.NO_PK, CTA.ADM_FEE, CTA.ID_BANK_GARANSI, CTA.JAMINAN, CHANNEL.CHANNEL_OWNER_L1, CHANNEL.CHANNEL_TYPE_L1, CHANNEL.CHANNEL_OWNER_L2, CHANNEL.CHANNEL_TYPE_L2, CHANNEL.CHANNEL_OWNER_L3, CHANNEL.CHANNEL_TYPE_L3, CHANNEL.CHANNEL_OWNER_MIRROR, CTA.AS_OF_DATE FROM ACL_DATALAKE.MART_CTA CTA LEFT JOIN DM_CUSTOMER.CUSTOMER_ICONS CUST ON CTA.CIF_KEY = CUST.CIF_KEY AND CUST.AS_OF_DATE = '{TANGGAL_POSISI}' LEFT JOIN (SELECT * FROM (SELECT CHANNEL.*, ROW_NUMBER() OVER(PARTITION BY ID_NUMBER ORDER BY AS_OF_DATE DESC) RN FROM (SELECT DISTINCT CIF_KEY, ID_NUMBER, SEGMENT_DIV_OWNER, CHANNEL_OWNER_L1, CHANNEL_TYPE_L1, CHANNEL_OWNER_L2, CHANNEL_TYPE_L2, CHANNEL_OWNER_L3, CHANNEL_TYPE_L3, CHANNEL_OWNER_MIRROR, AS_OF_DATE FROM acl_datalake.mart_master_channel_baseline UNION ALL SELECT CIF_KEY, ID_NUMBER, SEGMENT_DIV_OWNER, CHANNEL_OWNER_L1, CHANNEL_TYPE_L1, CHANNEL_OWNER_L2, CHANNEL_TYPE_L2, CHANNEL_OWNER_L3, CHANNEL_TYPE_L3, CHANNEL_OWNER_MIRROR, AS_OF_DATE FROM acl_datalake.mart_master_channel_nwow_daily) AS CHANNEL) AS CHANNEL WHERE RN = 1) AS CHANNEL ON CTA.ID_NUMBER = CHANNEL.ID_NUMBER AND CTA.AS_OF_DATE = CHANNEL.AS_OF_DATE;
INSERT INTO PRD_ACL_DATALAKE.MASTER_CTA PARTITION (as_of_date) SELECT * FROM #temp_table;
